#!/usr/bin/env python3
import base64, os

# /var/www/konverta/src/routes/collect.js
b64_collect = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/collect.js"), exist_ok=True)
open("/var/www/konverta/src/routes/collect.js", "wb").write(base64.b64decode(b64_collect))
print("✓ /var/www/konverta/src/routes/collect.js")

# /var/www/konverta/src/gtm-export.js
b64_gtm = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/gtm-export.js"), exist_ok=True)
open("/var/www/konverta/src/gtm-export.js", "wb").write(base64.b64decode(b64_gtm))
print("✓ /var/www/konverta/src/gtm-export.js")

# /var/www/konverta/src/routes/admin/index.js
b64_admin_js = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/admin/index.js"), exist_ok=True)
open("/var/www/konverta/src/routes/admin/index.js", "wb").write(base64.b64decode(b64_admin_js))
print("✓ /var/www/konverta/src/routes/admin/index.js")

# /var/www/konverta/public/admin.html
b64_admin_html = ""
os.makedirs(os.path.dirname("/var/www/konverta/public/admin.html"), exist_ok=True)
open("/var/www/konverta/public/admin.html", "wb").write(base64.b64decode(b64_admin_html))
print("✓ /var/www/konverta/public/admin.html")

print("\n✅ Todos os arquivos atualizados!")
os.system("pm2 restart konverta")